import React, { useState, useEffect } from 'react';
import './App.css';
import ChatInterface from './components/ChatInterface';
import FileUpload from './components/FileUpload';
import SessionManager from './components/SessionManager';
import { FaRobot, FaUpload, FaHistory, FaGraduationCap } from 'react-icons/fa';

function App() {
  const [currentView, setCurrentView] = useState('chat'); // 'chat', 'upload', 'sessions'
  const [currentSession, setCurrentSession] = useState('default');

  return (
    <div className="App">
      <header className="App-header">
        <div className="header-content">
          <div className="logo-section">
            <FaGraduationCap className="logo-icon" />
            <div className="title-section">
              <h1>期末复习问答助手</h1>
              <p>智能AI助手，帮助您高效复习期末考试</p>
            </div>
          </div>
          <nav className="nav-buttons">
            <button
              onClick={() => setCurrentView('chat')}
              className={currentView === 'chat' ? 'active' : ''}
            >
              <FaRobot className="nav-icon" />
              复习问答
            </button>
            <button
              onClick={() => setCurrentView('upload')}
              className={currentView === 'upload' ? 'active' : ''}
            >
              <FaUpload className="nav-icon" />
              知识库上传
            </button>
            <button
              onClick={() => setCurrentView('sessions')}
              className={currentView === 'sessions' ? 'active' : ''}
            >
              <FaHistory className="nav-icon" />
              会话管理
            </button>
          </nav>
        </div>
        <div className="header-decoration">
          <div className="floating-shapes">
            <div className="shape shape-1"></div>
            <div className="shape shape-2"></div>
            <div className="shape shape-3"></div>
          </div>
        </div>
      </header>

      <main>
        {currentView === 'chat' && (
          <ChatInterface
            sessionId={currentSession}
            onSessionChange={setCurrentSession}
          />
        )}
        {currentView === 'upload' && <FileUpload />}
        {currentView === 'sessions' && (
          <SessionManager
            onSessionSelect={setCurrentSession}
            currentSession={currentSession}
          />
        )}
      </main>
    </div>
  );
}

export default App;
